from smolagents import Agent
from collections import Counter

def detect_duplicate_tools(agent_outputs):
    tool_calls = []
    for output in agent_outputs:
        if hasattr(output, 'tool_calls'):
            tool_calls.extend(output.tool_calls)

    tool_counter = Counter(tool_calls)
    duplicates = {tool: count for tool, count in tool_counter.items() if count > 1}
    return len(duplicates) > 0

def detect_state_collisions(memory):
    collision_keys = []
    write_history = getattr(memory, '_write_history', {})

    for key in write_history:
        agents = set(write_history[key]['agents'])
        if len(agents) > 1:
            collision_keys.append(key)

    return len(collision_keys) > 0

def detect_context_loss(initial_context, final_context):
    missing_vars = []
    for var in initial_context:
        if var not in final_context:
            missing_vars.append(var)

    loss_rate = len(missing_vars) / len(initial_context)
    return loss_rate > 0.2

