from smolagents import Agent
from threading import Lock

class CoordinatedAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.resource_locks = {}

    def acquire_resource(self, resource_name):
        if resource_name not in self.resource_locks:
            self.resource_locks[resource_name] = Lock()
        self.resource_locks[resource_name].acquire()

    def release_resource(self, resource_name):
        self.resource_locks[resource_name].release()

from smolagents import MultiAgent
from collections import deque

class SequentialMultiAgent(MultiAgent):
    def __init__(self, agents):
        self.task_queue = deque()
        self.agents = {agent.name: agent for agent in agents}

    def run_sequential(self, tasks):
        for task in tasks:
            agent = self.agents[task['agent']]
            result = agent.run(task['input'])
            self.share_state(task['agent'], result)

